mapper.select:
SELECT ID, NAME, SAFETY_RATING, FLEET_SIZE, CONTACT_EMAIL, MAITENANCE_PROVIDER
FROM AIRLINES
WHERE ID = #{id}

SELECT ID, NAME, SAFETY_RATING, FLEET_SIZE, CONTACT_EMAIL, MAITENANCE_PROVIDER
FROM AIRLINES
WHERE NAME = #{name}

SELECT ID, NAME, SAFETY_RATING, FLEET_SIZE, CONTACT_EMAIL, MAITENANCE_PROVIDER
FROM AIRLINES
WHERE CONTACT_EMAIL = #{contactEmail}

SELECT ID, NAME, SAFETY_RATING, FLEET_SIZE, CONTACT_EMAIL, MAITENANCE_PROVIDER
FROM AIRLINES
WHERE MAITENANCE_PROVIDER = #{maintenanceProvider}

SELECT ID, NAME, SAFETY_RATING, FLEET_SIZE, CONTACT_EMAIL, MAITENANCE_PROVIDER
FROM AIRLINES
WHERE SAFETY_RATING > #{minRating}

SELECT ID, NAME, SAFETY_RATING, FLEET_SIZE, CONTACT_EMAIL, MAITENANCE_PROVIDER
FROM AIRLINES
WHERE FLEET_SIZE > #{minFleetSize}
